precision mediump float;
uniform float uTime;
uniform vec2  uResolution;
uniform vec2  uMouse;
varying vec2  vUv;

// 切り出した uniforms
uniform float uBumpStrength;       // 凹凸の強さ
uniform vec3  uBaseColor;          // 基本色
uniform vec3  uLightColor;         // 光源色
uniform float uAmbient;            // 環境光
uniform float uShininess;          // ハイライトの鋭さ (pow exponent)
uniform float uSpecStrength;   // ハイライト強度 (0.0 〜 1.0)
uniform float uExposure;       // 露出 (0.5 〜 2.0)
uniform float uMetallic;           // 0:matte 〜 1:metallic
uniform float uLightZ;             // ライト方向の z (小さいほど grazing)
uniform float uCursorRadius;       // カーソル光の届く範囲
uniform float uCursorBoost;        // カーソル光の最大ブースト量
uniform float uMetallicSpecGain;   // metallic 時のスペキュラ強度

float hash(vec2 p) { return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453); }
float vnoise(vec2 p) {
  vec2 i = floor(p), f = fract(p);
  vec2 u = f * f * (3.0 - 2.0 * f);
  return mix(mix(hash(i),                  hash(i + vec2(1.0, 0.0)), u.x),
             mix(hash(i + vec2(0.0, 1.0)), hash(i + vec2(1.0, 1.0)), u.x), u.y);
}

float height(vec2 uv) {
  float h = 0.0, amp = 0.5, freq = 5.0;
  for (int i = 0; i < 4; i++) {
    h    += vnoise(uv * freq) * amp;
    amp  *= 0.5;
    freq *= 2.0;
  }
  return h;
}

vec3 calcNormal(vec2 uv) {
  float eps = 0.003;
  float hL = height(uv - vec2(eps, 0.0));
  float hR = height(uv + vec2(eps, 0.0));
  float hD = height(uv - vec2(0.0, eps));
  float hU = height(uv + vec2(0.0, eps));
  return normalize(vec3((hL - hR) * uBumpStrength,
                        (hD - hU) * uBumpStrength,
                        1.0));
}

void main() {
  float aspect   = uResolution.x / uResolution.y;
  vec2  aspectUV = vUv * vec2(aspect, 1.0);

  vec2 cursor = uMouse;
  vec2 aspectCursor = cursor * vec2(aspect, 1.0);

  vec3 lightDir = normalize(vec3(aspectCursor - aspectUV, uLightZ));
  vec3 viewDir  = vec3(0.0, 0.0, 1.0);
  vec3 halfDir  = normalize(lightDir + viewDir);

  vec3 normal = calcNormal(vUv);
  float diff = max(0.0, dot(normal, lightDir));
  float spec = pow(max(0.0, dot(normal, halfDir)), uShininess);

  vec3 ambient = vec3(uAmbient);

     vec3 matteColor    = uBaseColor * (ambient + diff * uLightColor) + spec * uLightColor * uSpecStrength;
  vec3 metallicColor = uBaseColor * (ambient + diff * uLightColor) + spec * uBaseColor * uMetallicSpecGain * uSpecStrength;

  vec3 col = mix(matteColor, metallicColor, uMetallic);

  float lightDist   = length(aspectCursor - aspectUV);
  float cursorAtten = 1.0 - smoothstep(0.0, uCursorRadius, lightDist);
  col *= (1.0 - uCursorBoost * 0.5) + uCursorBoost * cursorAtten;

  // 露出 → Reinhard トーンマップ (clamp ではなく滑らかに 0..1 へ圧縮)
  col *= uExposure;
  col  = col / (1.0 + col);

  gl_FragColor = vec4(col, 1.0);
}

precision highp float;
  uniform float uTime;
  varying vec3 vNormal;
  varying vec2 vUv;

  // 切り出した uniforms
  uniform vec3  uBaseColor;       // 苔/岩肌のベース色
  uniform vec3  uDotColor;        // 通過済み点のグロー色
  uniform vec3  uBeamColor;       // ビーム自体の色
  uniform float uAmbient;         // 環境光率 (0=完全シェーディング, 1=ベタ平面)
  uniform float uScanInterval;    // スキャンの周期(秒)
  uniform float uScanSpeed;       // ビーム伝播速度
  uniform float uBeamWidth;       // ビームの太さ
