  uniform vec2  uGridSize;        // 点群グリッド分割数
  uniform float uDotSize;         // 点の基準サイズ
  uniform float uDotDensity;      // 点の存在率 (0..1, 1=全部存在)
  uniform float uDecayRate;       // 点灯後の減衰速度(大きいほど早く消える)

  float hash(vec2 p) { return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453); }

  void main() {
    // 1. ベース: 苔/岩肌の暗い緑(法線で軽くシェーディング)
    vec3 lightDir = normalize(vec3(0.4, 0.7, 0.8));
    float ndl = max(dot(vNormal, lightDir), 0.0);
    float shade = mix(ndl, 1.0, uAmbient);   // uAmbient=0.4 で元の "0.4+0.6*ndl" と等価
    vec3 baseColor = uBaseColor * shade;

    // 2. スキャン中心: uScanInterval 秒ごとに新しいランダム位置
    float scanT = floor(uTime / uScanInterval) * uScanInterval;
    vec2 scanUv = vec2(hash(vec2(scanT, 0.0)), 0.35 + 0.3 * hash(vec2(scanT, 1.0)));
    vec2 aspect = vec2(2.0, 1.0);   // 球面 UV の経度方向補正

    // 3. ビーム伝播
    float dToCenter = distance(vUv * aspect, scanUv * aspect);
    float elapsed = uTime - scanT;
    float waveFront = elapsed * uScanSpeed;
    float beam = exp(-pow((dToCenter - waveFront) / uBeamWidth, 2.0));
    beam *= step(0.0, waveFront - dToCenter + uBeamWidth * 1.5);

    // 4. 点群グリッド
    vec2 gridF = vUv * uGridSize;
    vec2 cell = floor(gridF);
    vec2 patchUV = fract(gridF) - 0.5;
    float dotR = length(patchUV);
    float cellSeed = hash(cell);
    // 元: dotSize = 0.15 + 0.20 * cellSeed  →  uDotSize=0.25 で同等(0.6〜1.4倍の揺らぎ)
    float dotSize = uDotSize * (0.6 + 0.8 * cellSeed);
    float dotMask = smoothstep(dotSize, dotSize * 0.5, dotR);
    // uDotDensity=0.6 で元の "step(0.4, cellSeed)" と等価
    dotMask *= step(1.0 - uDotDensity, cellSeed);

    // 5. 各点のスキャン到達時刻 = セル中心からの距離 / speed
    vec2 cellCenter = (cell + 0.5) / uGridSize;
    float dCellToCenter = distance(cellCenter * aspect, scanUv * aspect);
    float hitTime = dCellToCenter / uScanSpeed;
    float passed = max(0.0, elapsed - hitTime);
    float lit = passed > 0.0 ? exp(-passed * uDecayRate) : 0.0;

    // 6. 合成
    vec3 color = baseColor;
    color = mix(color, uDotColor, dotMask * lit);
    color += beam * uBeamIntensity * uBeamColor;
    color *= 0.95 + 0.1 * ndl;
    gl_FragColor = vec4(color, 1.0);
  }

