precision highp float;

uniform vec3  uColorBase;
uniform float uAmbient;
uniform float uDissolveProgress;
uniform float uDissolveAngle;     // 0..360 deg
uniform float uOffsetWindow;      // 本物の maxOffsetRatio
uniform float uCutoff;            // discard しきい値

varying vec3 vNormal;
varying vec2 vPosXY;

float getAnimationValue(float aValue, float randomValue, float minOffsetRatio, float maxOffsetRatio) {
  float offsetRatio   = minOffsetRatio + (maxOffsetRatio - minOffsetRatio) * randomValue;
  float durationRatio = 1.0 - maxOffsetRatio;
  float v = max(0.0, aValue - offsetRatio);
  return clamp(v / durationRatio, 0.0, 1.0);
}

float cubicInOut(float t) {
  return t < 0.5 ? 4.0*t*t*t : 0.5*pow(2.0*t - 2.0, 3.0) + 1.0;
}

void main() {
  // 「animationOffset が増える方向」のベクトル。0°→(0,1) で上向き = 下から消える
  // 90°→(-1,0) で左向き = 右から消える。time-rotation を入れずに固定軸として使う。
  float angleRad = radians(uDissolveAngle);
  vec2  axisDir  = vec2(-sin(angleRad), cos(angleRad));

  // pos.xy を axisDir に射影 → [-1, 1] → [0, 1]
  float projected       = dot(vPosXY, axisDir);
  float animationOffset = clamp((projected + 1.0) * 0.5, 0.0, 1.0);

  // 本物の getAnimationValue + cubicInOut をピクセル単位に評価 (砂目ノイズも三角形ジャギーも出ない)
  float dissolveLinear = getAnimationValue(uDissolveProgress, animationOffset, 0.0, uOffsetWindow);
  float boost          = cubicInOut(dissolveLinear);

  if (boost > uCutoff) discard;

  vec3 n = normalize(vNormal);
  vec3 L = normalize(vec3(0.5, 0.8, 1.0));
  float diff = max(dot(n, L), 0.0);
  float shade = uAmbient + (1.0 - uAmbient) * diff;
  gl_FragColor = vec4(uColorBase * shade, 1.0);
}

