uniform float uTime;
  uniform float uDissolveProgress;  // 0..1, 主役の lil-gui slider
  uniform float uDissolveAngle;     // 0..360 deg。0=下から/90=右から/180=上から/270=左から
  uniform float uTorusR;            // リング半径
  uniform float uTorusr;            // チューブ半径
  uniform float uExplodeDist;       // 発火後の外向き push 距離
  uniform float uCurlScale;         // curlNoise 入力倍率 (本物 noiseScale)
  uniform float uCurlStrength;      // curlNoise 出力倍率 (本物 curlStrength)
  uniform float uDriftSpeed;        // 散布粒の時間進行速度 (curl 場の advection + 個体軌道に共通)
  uniform float uDriftAmplitude;    // 個体ごとの sin/cos 軌道の振幅
  uniform float uParticleSize;
  uniform float uOffsetWindow;      // getAnimationValue の maxOffsetRatio (本物 0.7)

  varying float vBoost;
  varying float vY;

  // === 本物の snoise (3D Simplex, Ashima Arts) ===
  vec3 mod289(vec3 x){ return x - floor(x*(1.0/289.0))*289.0; }
  vec4 mod289(vec4 x){ return x - floor(x*(1.0/289.0))*289.0; }
  vec4 permute(vec4 x){ return mod289(((x*34.0)+1.0)*x); }
  vec4 taylorInvSqrt(vec4 r){ return 1.79284291400159 - 0.85373472095314*r; }
  float snoise(vec3 v){
    const vec2 C = vec2(1.0/6.0, 1.0/3.0);
    const vec4 D = vec4(0.0, 0.5, 1.0, 2.0);
    vec3 i  = floor(v + dot(v, C.yyy));
    vec3 x0 = v - i + dot(i, C.xxx);
    vec3 g  = step(x0.yzx, x0.xyz);
    vec3 l  = 1.0 - g;
    vec3 i1 = min(g.xyz, l.zxy);
    vec3 i2 = max(g.xyz, l.zxy);
    vec3 x1 = x0 - i1 + C.xxx;
    vec3 x2 = x0 - i2 + C.yyy;
    vec3 x3 = x0 - D.yyy;
    i = mod289(i);
    vec4 p = permute(permute(permute(
              i.z + vec4(0.0, i1.z, i2.z, 1.0))
            + i.y + vec4(0.0, i1.y, i2.y, 1.0))
            + i.x + vec4(0.0, i1.x, i2.x, 1.0));
    vec3 ns = (1.0/7.0)*D.wyz - D.xzx;
    vec4 j  = p - 49.0*floor(p*ns.z*ns.z);
    vec4 x_ = floor(j*ns.z);
    vec4 y_ = floor(j - 7.0*x_);
    vec4 x  = x_*ns.x + ns.yyyy;
    vec4 y  = y_*ns.x + ns.yyyy;
    vec4 h  = 1.0 - abs(x) - abs(y);
    vec4 b0 = vec4(x.xy, y.xy);
    vec4 b1 = vec4(x.zw, y.zw);
    vec4 s0 = floor(b0)*2.0 + 1.0;
    vec4 s1 = floor(b1)*2.0 + 1.0;
    vec4 sh = -step(h, vec4(0.0));
    vec4 a0 = b0.xzyw + s0.xzyw*sh.xxyy;
    vec4 a1 = b1.xzyw + s1.xzyw*sh.zzww;
    vec3 p0 = vec3(a0.xy, h.x);
    vec3 p1 = vec3(a0.zw, h.y);
    vec3 p2 = vec3(a1.xy, h.z);
    vec3 p3 = vec3(a1.zw, h.w);
    vec4 norm = taylorInvSqrt(vec4(dot(p0,p0), dot(p1,p1), dot(p2,p2), dot(p3,p3)));
    p0 *= norm.x; p1 *= norm.y; p2 *= norm.z; p3 *= norm.w;
    vec4 m = max(0.6 - vec4(dot(x0,x0), dot(x1,x1), dot(x2,x2), dot(x3,x3)), 0.0);
    m = m*m;
    return 42.0 * dot(m*m, vec4(dot(p0,x0), dot(p1,x1), dot(p2,x2), dot(p3,x3)));
  }

  // === 本物の curlNoise (snoise の中心差分で curl 場) ===
  vec3 curlNoise(vec3 p, float t) {
    float e  = 0.1;
    vec3  p1 = p + vec3(t * 0.05);
    float dx = snoise(p1 + vec3(e, 0.0, 0.0)) - snoise(p1 - vec3(e, 0.0, 0.0));
    float dy = snoise(p1 + vec3(0.0, e, 0.0)) - snoise(p1 - vec3(0.0, e, 0.0));
    float dz = snoise(p1 + vec3(0.0, 0.0, e)) - snoise(p1 - vec3(0.0, 0.0, e));
    return vec3(dz - dy, dx - dz, dy - dx) / (2.0 * e);
  }

  // === 本物の getAnimationValue: progress を [offsetRatio, 1] に再マップして [0,1] へ正規化 ===
  // 第2引数 (本物の randomValue 位置) に animationOffset を入れると、指定方向で発火タイミングが連続的に並ぶ。
  float getAnimationValue(float aValue, float randomValue, float minOffsetRatio, float maxOffsetRatio) {
    float offsetRatio   = minOffsetRatio + (maxOffsetRatio - minOffsetRatio) * randomValue;
    float durationRatio = 1.0 - maxOffsetRatio;
    float v = max(0.0, aValue - offsetRatio);
    return clamp(v / durationRatio, 0.0, 1.0);
  }

  // === 本物の cubicInOut ===
  float cubicInOut(float t) {
    return t < 0.5 ? 4.0*t*t*t : 0.5*pow(2.0*t - 2.0, 3.0) + 1.0;
  }

  // === hash: position から 0..1 のスカラ ===
  float hash13(vec3 p) {
    p = fract(p * 0.3183099 + 0.1);
    p *= 17.0;
    return fract(p.x * p.y * p.z * (p.x + p.y + p.z));
  }

  const float TAU = 6.28318530718;

  void main() {
    // === preview_template の球内ランダム位置を hash で torus 表面 (theta, phi) に再配置 ===
    float theta = hash13(position * 7.13) * TAU;   // リング上の角度
    float phi   = hash13(position * 13.7) * TAU;   // チューブ断面の角度
    float seedRand = hash13(position * 21.1);      // 個体差用 (色・サイズの微ゆらぎ)

    vec3 torusPos = vec3(
      (uTorusR + uTorusr * cos(phi)) * cos(theta),
      uTorusr * sin(phi),
      (uTorusR + uTorusr * cos(phi)) * sin(theta)
    );

    // === 任意角度方向に射影して animationOffset を作る (本物の reverseOffset を回転拡張) ===
    // axisDir = 「animationOffset が増える方向」。0°→(0,1) 上向き = 下から消える、
    // 90°→(-1,0) 左向き = 右から消える、180°→(0,-1) = 上から消える、270°→(1,0) = 左から消える。
    float angleRad = radians(uDissolveAngle);
    vec2  axisDir  = vec2(-sin(angleRad), cos(angleRad));
    float projected = dot(torusPos.xy, axisDir);
    float radiusSum = uTorusR + uTorusr;
    float animationOffset = clamp((projected + radiusSum) / (2.0 * radiusSum), 0.0, 1.0);

    // === 本物の getAnimationValue + cubicInOut ===
    float dissolveLinear = getAnimationValue(uDissolveProgress, animationOffset, 0.0, uOffsetWindow);
    float dissolveEased  = cubicInOut(dissolveLinear);

    // === 発火した粒を外側に飛ばす ===
    // (a) torus の外向き法線 (リング中心からの方向)
    vec3 ringCenter = vec3(uTorusR * cos(theta), 0.0, uTorusR * sin(theta));
    vec3 outward    = normalize(torusPos - ringCenter);

    // (b) curlNoise で乱流的な動き。
    // 本物は GPGPU で毎フレーム積分するので curlNoise の場自体は変化が遅い (time*0.001)。
    // ステートレスな単一パスでは「場を時間で大きく advect する」ことで散布粒が漂流する見え方を作る。
    vec3 noiseInput = torusPos * uCurlScale + vec3(uTime * uDriftSpeed * 0.3);
    vec3 curlForce  = curlNoise(noiseInput, uTime * 0.05) * uCurlStrength;

    // (c) 個体ごとの軌道 (発火粒の漂流) — 位相を seedRand でずらして粒同士が同期しないようにする
    vec3 orbit = vec3(
      sin(uTime * uDriftSpeed       + seedRand * 6.2831),
      cos(uTime * uDriftSpeed * 0.7 + seedRand * 9.4247),
      sin(uTime * uDriftSpeed * 0.5 + seedRand * 12.566)
    ) * uDriftAmplitude;

    // 個体差で発火距離をばらつかせる (本物 forceCoefficient)
    float forceCoefficient = 0.5 + 0.7 * seedRand;
    vec3 explodeVec = (outward * uExplodeDist + curlForce + orbit) * forceCoefficient;

    // dissolveEased で wrap: 未発火 (eased=0) の粒には curl も orbit も乗らず torus 形を維持する
    vec3 displaced = torusPos + explodeVec * dissolveEased;

    vBoost = dissolveEased;
    vY     = animationOffset;  // FS で色のグラデにも使う

    vec4 mv = modelViewMatrix * vec4(displaced, 1.0);
    // 発火した粒は少しずつ小さくなる (本物の DOF / flicker の代用、見た目の差別化)
    gl_PointSize = uParticleSize / -mv.z * (1.0 - 0.4 * dissolveEased);
    gl_Position  = projectionMatrix * mv;
  }

code.glsl:
precision highp float;

 uniform vec3  uColor;    // ステッカー色 (デフォルト赤)
 uniform float uAmbient;  // 周囲光
 uniform float uDiffuse;  // diffuse 強度

 varying vec2  vUv;
 varying vec3  vNormal;
 varying float vCurlAmount;

 void main() {
   // 円形マスク
   vec2 cuv = vUv - 0.5;
   float r = length(cuv);
   float mask = smoothstep(0.50, 0.49, r);
   if (mask < 0.005) discard;

   // 陰影(curl 角度で出る)
   vec3 N = normalize(vNormal);
   vec3 L = normalize(vec3(0.35, 0.7, 0.55));
   float diff = max(dot(N, L), 0.0);
   vec3 col = uColor * (uAmbient + uDiffuse * diff);

   // 巻きの裏側を少し暗く
   float backside = smoothstep(1.6, 3.2, vCurlAmount);
   col *= mix(1.0, 0.55, backside);

   gl_FragColor = vec4(col, mask);
 }

