uniform float uTime;        // テンプレ自動セット (今回 vertex では使わない)
uniform float uProgress;    // 0: 全部ロール / 1: 全部 flat
uniform float uCurlRadius;  // 巻き半径 (小さいほどタイトな curl)
uniform float uPeelLift;    // 剥がれ際を少し z にリフト (浮き上がり感)

varying vec2 vUv;
varying vec3 vNormal;
varying float vCurlAmount;  // 0=flat, 大きいほど巻き角度大 → FS でうっすら影に

void main() {
  vec3 p = position;          // plane(2,2,64,64): x,y ∈ [-1, 1]
  vec3 n = vec3(0.0, 0.0, 1.0);

  // 巻き境界。progress=0 → xb=-1 (左端=全部 roll)、progress=1 → xb=+1 (全部 flat)
  float xb = mix(-1.0, 1.0, uProgress);
  float d  = p.x - xb;

  float curlA = 0.0;
  if (d > 0.0) {
    float r = max(uCurlRadius, 0.001);
    float theta = d / r;                                   // 弧長 d を角度に
    p.x = xb + r * sin(theta);                             // 円柱上の x
    p.z = r * (1.0 - cos(theta));                          // 円柱上の z (上方向)
    n   = vec3(sin(theta), 0.0, cos(theta));               // 円柱表面の法線
    curlA = theta;
  } else {
    // 平面側: 剥がれ直前 (境界に近い flat 部分) をほんの少しだけ持ち上げ、
    // 浮き上がり感を出す。距離で減衰。
    float lift = exp(-pow((xb - p.x) * 6.0, 2.0)) * uPeelLift;
    p.z += lift;
  }

  vUv = uv;
  vNormal = normalize(normalMatrix * n);
  vCurlAmount = curlA;

  gl_Position = projectionMatrix * modelViewMatrix * vec4(p, 1.0);
}
